sql:
SELECT name
FROM practicals
WHERE practical_id NOT IN (SELECT practical_id FROM submissions);

SELECT name, date_assigned, description, grading_scheme
FROM practicals
WHERE is_graded = 1 AND is_submitted = 1;

external_knowledge:
- "Seeds" metaphorically refer to the original practical assignments (original_practical_id).;
- "Sprouted" indicates the presence of these original assignments in the assignment_reuse table, symbolizing the reuse or replication of these assignments as different practical tasks.;
- The garden represents the assignment_reuse table where these seeds grow and multiply without duplication.

sql:
SELECT student_id
FROM students
WHERE student_id NOT IN (
    SELECT DISTINCT student_id
    FROM submissions
);

SELECT DISTINCT s.student_name 
FROM students s 
JOIN submissions sub ON s.student_id = sub.student_id;

SELECT practicals.name
FROM practicals
INNER JOIN assignment_reuse ON practicals.practical_id = assignment_reuse.new_practical_id;

SELECT AVG(student_id) 
FROM students 
WHERE student_id NOT IN (SELECT student_id FROM submissions);

SELECT student_id, AVG(grade) AS average_grade
FROM submissions
GROUP BY student_id;

external_knowledge:
- "Past their submission deadlines" refers to assignments with a deadline that is earlier than the current date;
- "Collected fruits" metaphorically represent the student's submissions;
- "Paths where these fruits are stored" refers to the file paths of the submitted assignments;
- "Allowed only one attempt" means the `max_attempts` is equal to 1;
- "Syllabus garden" is used to symbolize the educational curriculum where each assignment has a specific location or page in the syllabus.

sql:
SELECT COUNT(*)
FROM practicals
WHERE max_attempts > 1 AND grading_scheme = 'percentage';

SELECT practicals.name
FROM practicals
WHERE practicals.max_attempts = (
    SELECT MAX(max_attempts) 
    FROM practicals
);
